import React, { useState } from "react";
import api from "../../api"; // axios instance

const SendEmailPage = () => {
  const [to, setTo] = useState("");
  const [subject, setSubject] = useState("");
  const [html, setHtml] = useState("");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState("");

  const handleSend = async () => {
    setLoading(true);
    setResult("");

    try {
      const res = await api.post("/email/send", {
        subject,
        group: "all", // test đơn giản → backend sẽ gửi cho "to"
        html: html,
        testEmail: to, // gửi 1 người
      });

      setResult("✅ Gửi thành công! Check Mailtrap.");
    } catch (err) {
      console.error(err);
      setResult("❌ Gửi thất bại. Kiểm tra backend.");
    }

    setLoading(false);
  };

  return (
    <div style={{ padding: 20, maxWidth: 600 }}>
      <h1 style={{ fontSize: 24, marginBottom: 20 }}>✨ Test gửi email đơn giản</h1>

      <label>Email người nhận:</label>
      <input
        value={to}
        onChange={(e) => setTo(e.target.value)}
        placeholder="test@example.com"
        style={{ width: "100%", padding: 10, marginBottom: 15, border: "1px solid #ccc" }}
      />

      <label>Subject:</label>
      <input
        value={subject}
        onChange={(e) => setSubject(e.target.value)}
        placeholder="Tiêu đề email"
        style={{ width: "100%", padding: 10, marginBottom: 15, border: "1px solid #ccc" }}
      />

      <label>HTML:</label>
      <textarea
        value={html}
        onChange={(e) => setHtml(e.target.value)}
        placeholder="<h1>Hello</h1>"
        style={{ width: "100%", height: 150, padding: 10, border: "1px solid #ccc" }}
      />

      <button
        onClick={handleSend}
        disabled={loading}
        style={{
          marginTop: 20,
          width: "100%",
          padding: 12,
          background: "#e06c7f",
          color: "white",
          fontWeight: "bold",
          border: "none",
          cursor: "pointer",
        }}
      >
        {loading ? "Đang gửi..." : "📨 Gửi Email"}
      </button>

      {result && (
        <p style={{ marginTop: 20, fontWeight: "bold" }}>
          {result}
        </p>
      )}
    </div>
  );
};

export default SendEmailPage;
